const data = msg.payload;

// Extraer datos del mensaje de FoxES
const miappData = {
    power: data.power || 0,
    voltage: data.voltage || 220,
    current: data.current || 0,
    energyToday: data.todayYield || 0,
    solarPower: data.pvPower || 0,
    batterySoc: data.batterySoc || 0,
    gridConsumption: data.gridConsumption || 0,
    loadsPower: data.loadsPower || 0
};

msg.payload = miappData;
return msg;

try {
    const result = msg.payload.result || [];
    if (result.length > 0) {
        const data = result[0].data || {};
        msg.payload = {
            power: data.pvPower * 1000 || 0,
            voltage: 220,
            current: data.pvPower * 1000 / 220 || 0,
            energyToday: data.todayYield || 0,
            solarPower: data.pvPower * 1000 || 0,
            batterySoc: data.batterySoc || 0,
            gridConsumption: data.gridConsumption * 1000 || 0,
            loadsPower: data.loadsPower * 1000 || 0
        };
    }
} catch (e) {
    msg.payload = {};
}
return msg;
